#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n;    cin >> n;    string s;    cin >> s;    int count=1;    int longest_length=1;     for(int i=1;i<n;i++){        if(s[i]=='<'&& s[i-1] =='<' ||s[i]=='>'&& s[i-1] =='>'){            count++;            longest_length=max(longest_length, count);         }        else {            count=1;        }            }    cout<<longest_length+1<<endl;}             // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}